def {{nama_fungsi}}(text: str) -> int:
    """Estimasi kasar jumlah token: panjang karakter dibagi {{chars_per_token}}.
    Untuk perhitungan presisi, gunakan tokenizer resmi provider model kamu."""
    if not text:
        return 0
    return max(1, len(text) // {{chars_per_token}})

def {{nama_fungsi}}(input_tokens: int, output_tokens: int, price_per_1k_input: float, price_per_1k_output: float) -> float:
    """Kembalikan estimasi biaya dalam satuan mata uang yang sama dengan tarif yang dimasukkan."""
    input_cost = (input_tokens / 1000) * price_per_1k_input
    output_cost = (output_tokens / 1000) * price_per_1k_output
    return round(input_cost + output_cost, 6)

class {{nama_kelas}}:
    """Pengelola riwayat percakapan sederhana, menyimpan maksimal {{max_history}} pesan terakhir."""

    def __init__(self):
        self._history = []
        self._max_history = {{max_history}}

    def add(self, role: str, content: str):
        self._history.append({"role": role, "content": content})
        if len(self._history) > self._max_history:
            self._history = self._history[-self._max_history:]

    def get_all(self):
        return list(self._history)

    def clear(self):
        self._history = []

    def as_text(self) -> str:
        return "\n".join(f"{m['role']}: {m['content']}" for m in self._history)
